# Configure logging
logger = logging.getLogger()
logger.setLevel(logging.INFO)

# Initialize AWS clients
s3_client = boto3.client('s3')
sns_client = boto3.client('sns')
rekognition_client = boto3.client('rekognition')

# Environment variables
RESULTS_BUCKET = os.environ.get('RESULTS_BUCKET', 'image-processing-results')
SNS_TOPIC_ARN = os.environ.get('SNS_TOPIC_ARN', '')
CONFIDENCE_THRESHOLD = float(os.environ.get('CONFIDENCE_THRESHOLD', '80.0'))
MAX_LABELS = int(os.environ.get('MAX_LABELS', '20'))

# Allowed image extensions
ALLOWED_EXTENSIONS = {'.jpg', '.jpeg', '.png', '.bmp', '.gif'}
# Maximum file size: 15 MB (Rekognition limit for S3 is 15MB)
MAX_FILE_SIZE_BYTES = 15 * 1024 * 1024


def validate_image_key(key):
    """Validate that the S3 key refers to an allowed image file type."""
    key_lower = key.lower()
    for ext in ALLOWED_EXTENSIONS:
        if key_lower.endswith(ext):
            return True
    return False


def get_object_metadata(bucket, key):
    """Retrieve object metadata and validate file size."""
    try:
        response = s3_client.head_object(Bucket=bucket, Key=key)
        content_length = response.get('ContentLength', 0)
        content_type = response.get('ContentType', '')
        return {
            'content_length': content_length,
            'content_type': content_type,
            'last_modified': str(response.get('LastModified', '')),
        }
    except s3_client.exceptions.ClientError as e:
        logger.error(f"Failed to get metadata for s3://{bucket}/{key}: {e}")
        raise


def detect_labels(bucket, key):
    """Use AWS Rekognition to detect labels in the image."""
    try:
        response = rekognition_client.detect_labels(
            Image={
                'S3Object': {
                    'Bucket': bucket,
                    'Name': key
                }
            },
            MaxLabels=MAX_LABELS,
            MinConfidence=CONFIDENCE_THRESHOLD
        )
        labels = []
        for label in response.get('Labels', []):
            label_info = {
                'name': label['Name'],
                'confidence': round(label['Confidence'], 2),
                'categories': [cat.get('Name', '') for cat in label.get('Categories', [])],
                'parents': [p['Name'] for p in label.get('Parents', [])],
            }
            # Include bounding boxes if present
            if label.get('Instances'):
                label_info['instances'] = [
                    {
                        'confidence': round(inst['Confidence'], 2),
                        'bounding_box': inst.get('BoundingBox', {})
                    }
                    for inst in label['Instances']
                ]
            labels.append(label_info)
        return labels
    except rekognition_client.exceptions.InvalidS3ObjectException as e:
        logger.error(f"Invalid S3 object for Rekognition: {e}")
        raise
    except rekognition_client.exceptions.ImageTooLargeException as e:
        logger.error(f"Image too large for Rekognition: {e}")
        raise
    except Exception as e:
        logger.error(f"Rekognition detect_labels failed: {e}")
        raise


def detect_moderation_labels(bucket, key):
    """Use AWS Rekognition to detect moderation labels (unsafe content)."""
    try:
        response = rekognition_client.detect_moderation_labels(
            Image={
                'S3Object': {
                    'Bucket': bucket,
                    'Name': key
                }
            },
            MinConfidence=CONFIDENCE_THRESHOLD
        )
        moderation_labels = [
            {
                'name': label['Name'],
                'confidence': round(label['Confidence'], 2),
                'parent_name': label.get('ParentName', ''),
            }
            for label in response.get('ModerationLabels', [])
        ]
        return moderation_labels
    except Exception as e:
        logger.error(f"Rekognition detect_moderation_labels failed: {e}")
        raise


def detect_faces(bucket, key):
    """Use AWS Rekognition to detect faces in the image."""
    try:
        response = rekognition_client.detect_faces(
            Image={
                'S3Object': {
                    'Bucket': bucket,
                    'Name': key
                }
            },
            Attributes=['ALL']
        )
        faces = []
        for face in response.get('FaceDetails', []):
            face_info = {
                'confidence': round(face.get('Confidence', 0), 2),
                'bounding_box': face.get('BoundingBox', {}),
                'age_range': face.get('AgeRange', {}),
                'gender': face.get('Gender', {}),
                'emotions': [
                    {
                        'type': emotion['Type'],
                        'confidence': round(emotion['Confidence'], 2)
                    }
                    for emotion in face.get('Emotions', [])
                    if emotion['Confidence'] >= CONFIDENCE_THRESHOLD
                ],
                'smile': face.get('Smile', {}),
                'eyeglasses': face.get('Eyeglasses', {}),
                'sunglasses': face.get('Sunglasses', {}),
            }
            faces.append(face_info)
        return faces
    except Exception as e:
        logger.error(f"Rekognition detect_faces failed: {e}")
        raise


def save_results_to_s3(results, source_bucket, source_key):
    """Save processing results as JSON to the results S3 bucket."""
    # Create a results key based on the source key
    result_key = f"results/{source_key.rsplit('.', 1)[0]}_{results['processing_id']}.json"

    try:
        s3_client.put_object(
            Bucket=RESULTS_BUCKET,
            Key=result_key,
            Body=json.dumps(results, indent=2, default=str),
            ContentType='application/json',
            ServerSideEncryption='AES256',
            Metadata={
                'source-bucket': source_bucket,
                'source-key': source_key,
                'processing-id': results['processing_id'],
            }
        )
        logger.info(f"Results saved to s3://{RESULTS_BUCKET}/{result_key}")
        return result_key
    except Exception as e:
        logger.error(f"Failed to save results to S3: {e}")
        raise


def send_sns_notification(results, result_key, status='SUCCESS'):
    """Send processing notification via SNS."""
    if not SNS_TOPIC_ARN:
        logger.warning("SNS_TOPIC_ARN not configured, skipping notification")
        return None

    label_names = [label['name'] for label in results.get('labels', [])[:5]]
    face_count = len(results.get('faces', []))
    moderation_count = len(results.get('moderation_labels', []))

    subject = f"Image Processing {status}: {results.get('source_key', 'unknown')}"

    message = {
        'processing_id': results.get('processing_id', ''),
        'status': status,
        'source_bucket': results.get('source_bucket', ''),
        'source_key': results.get('source_key', ''),
        'result_location': f"s3://{RESULTS_BUCKET}/{result_key}",
        'summary': {
            'labels_detected': len(results.get('labels', [])),
            'top_labels': label_names,
            'faces_detected': face_count,
            'moderation_flags': moderation_count,
            'has_unsafe_content': moderation_count > 0,
        },
        'processed_at': results.get('processed_at', ''),
    }

    try:
        response = sns_client.publish(
            TopicArn=SNS_TOPIC_ARN,
            Subject=subject[:100],  # SNS subject max 100 chars
            Message=json.dumps(message, indent=2, default=str),
            MessageAttributes={
                'status': {
                    'DataType': 'String',
                    'StringValue': status
                },
                'has_unsafe_content': {
                    'DataType': 'String',
                    'StringValue': str(moderation_count > 0)
                }
            }
        )
        logger.info(f"SNS notification sent: {response.get('MessageId')}")
        return response.get('MessageId')
    except Exception as e:
        logger.error(f"Failed to send SNS notification: {e}")
        # Don't raise - notification failure shouldn't fail the whole process
        return None


def send_error_notification(source_bucket, source_key, error_message):
    """Send error notification via SNS."""
    if not SNS_TOPIC_ARN:
        return None

    subject = f"Image Processing FAILED: {source_key}"
    message = {
        'status': 'FAILED',
        'source_bucket': source_bucket,
        'source_key': source_key,
        'error': str(error_message),
        'timestamp': datetime.utcnow().isoformat(),
    }

    try:
        response = sns_client.publish(
            TopicArn=SNS_TOPIC_ARN,
            Subject=subject[:100],
            Message=json.dumps(message, indent=2, default=str),
            MessageAttributes={
                'status': {
                    'DataType': 'String',
                    'StringValue': 'FAILED'
                }
            }
        )
        return response.get('MessageId')
    except Exception as e:
        logger.error(f"Failed to send error notification: {e}")
        return None


